610	/// Minimal `luaK_dischargevars` covering the cases the parser bootstrap can
611	/// produce: `VUpVal`, `VIndexUp`, `VKStr`. Other variants are left untouched.
612	/// Returns Ok(()) on success.
613	fn cg_discharge_vars(
614	    fs: &mut FuncState,
615	    line: i32,
616	    e: &mut ExprDesc,
617	) -> Result<(), LuaError> {
618	    match e.k {
619	        ExprKind::UpVal => {
620	            let inst = lua_code::opcodes::Instruction::abck(
621	                lua_code::opcodes::OpCode::GetUpVal,
622	                0,
623	                e.u.info as u32,
624	                0,
625	                0,
626	            );
627	            let pc = emit_inst(fs, line, inst);
628	            e.u.info = pc;
629	            e.k = ExprKind::Reloc;
630	        }
631	        ExprKind::IndexUp => {
632	            let inst = lua_code::opcodes::Instruction::abck(
633	                lua_code::opcodes::OpCode::GetTabUp,
634	                0,
635	                e.u.ind_t as u32,
636	                e.u.ind_idx as u32,
637	                0,
638	            );
639	            let pc = emit_inst(fs, line, inst);
640	            e.u.info = pc;
641	            e.k = ExprKind::Reloc;
642	        }
643	        _ => {}
644	    }
645	    Ok(())
646	}
