648	/// Minimal `luaK_exp2nextreg`: discharge `e` and place it in `fs.freereg`,
649	/// incrementing `freereg`. Handles `VReloc`, `VKStr`, `VKInt`, `VKFlt`,
650	/// `VNil`, `VTrue`, `VFalse`, `VNonReloc` plus anything `cg_discharge_vars`
651	/// produces.
652	fn cg_exp_to_next_reg(
653	    fs: &mut FuncState,
654	    line: i32,
655	    e: &mut ExprDesc,
656	) -> Result<(), LuaError> {
657	    cg_discharge_vars(fs, line, e)?;
658	    let reg = reserve_reg(fs);
659	    match e.k {
660	        ExprKind::Reloc => {
661	            let pc = e.u.info as usize;
662	            let mut lc = lua_code::opcodes::Instruction(fs.f.code[pc].0);
663	            lc.set_arg_a(reg as u32);
664	            fs.f.code[pc] = lua_types::opcode::Instruction::new(lc.0);
665	        }
666	        ExprKind::KStr => {
667	            let s = e.u.strval.clone()
668	                .ok_or_else(|| LuaError::syntax(format_args!("internal: VKStr with no strval")))?;
669	            let k_idx = add_k_string(fs, s);
670	            let inst = lua_code::opcodes::Instruction::abx(
671	                lua_code::opcodes::OpCode::LoadK,
672	                reg as u32,
673	                k_idx as u32,
674	            );
675	            emit_inst(fs, line, inst);
676	        }
677	        ExprKind::Nil => {
678	            let inst = lua_code::opcodes::Instruction::abck(
679	                lua_code::opcodes::OpCode::LoadNil, reg as u32, 0, 0, 0,
680	            );
681	            emit_inst(fs, line, inst);
682	        }
683	        ExprKind::True => {
684	            let inst = lua_code::opcodes::Instruction::abck(
685	                lua_code::opcodes::OpCode::LoadTrue, reg as u32, 0, 0, 0,
686	            );
687	            emit_inst(fs, line, inst);
688	        }
689	        ExprKind::False => {
690	            let inst = lua_code::opcodes::Instruction::abck(
691	                lua_code::opcodes::OpCode::LoadFalse, reg as u32, 0, 0, 0,
692	            );
693	            emit_inst(fs, line, inst);
694	        }
695	        ExprKind::NonReloc => {
696	            if e.u.info as u8 != reg {
697	                let inst = lua_code::opcodes::Instruction::abck(
698	                    lua_code::opcodes::OpCode::Move,
699	                    reg as u32,
700	                    e.u.info as u32,
701	                    0, 0,
702	                );
703	                emit_inst(fs, line, inst);
704	            }
705	        }
706	        _ => {
707	            return Err(LuaError::syntax(format_args!(
708	                "internal: cg_exp_to_next_reg cannot discharge {:?}", e.k
709	            )));
710	        }
711	    }
712	    e.u.info = reg as i32;
713	    e.k = ExprKind::NonReloc;
714	    Ok(())
715	}
