725	/// C: static l_noret error_expected(LexState *ls, int token)
726	/// Constructs a syntax error for a missing expected token.
727	/// In Rust, `l_noret` becomes returning `LuaError`; callers use
728	/// `return Err(error_expected(...))`.
729	fn error_expected(ls: &LexState, token: TokenKind) -> LuaError {
730	    // C: luaX_syntaxerror(ls, luaO_pushfstring(ls->L, "%s expected", luaX_token2str(ls, token)));
731	    // TODO(port): lua_lex::token_to_str(ls, token) for the token name
732	    let _ = ls;
733	    LuaError::syntax(format_args!("{} expected", token))
734	}
