736	/// C: static l_noret errorlimit(FuncState *fs, int limit, const char *what)
737	/// Constructs a compile-time limit-exceeded syntax error.
738	fn error_limit(fs: &FuncState, limit: i32, what: &str) -> LuaError {
739	    // C: line == 0 ? "main function" : "function at line %d"
740	    let line = fs.f.linedefined;
741	    if line == 0 {
742	        LuaError::syntax(format_args!(
743	            "too many {} (limit is {}) in main function", what, limit
744	        ))
745	    } else {
746	        LuaError::syntax(format_args!(
747	            "too many {} (limit is {}) in function at line {}", what, limit, line
748	        ))
749	    }
750	}
