827	/// C: static int registerlocalvar(LexState *ls, FuncState *fs, TString *varname)
828	/// Registers a local variable in the proto's debug-info locvars array.
829	/// Returns the index in locvars (= fs->ndebugvars before increment).
830	fn register_local_var(
831	    ls: &mut LexState,
832	    state: &mut LuaState,
833	    fs: &mut FuncState,
834	    varname: GcRef<LuaString>,
835	) -> Result<i32, LuaError> {
836	    // C: luaM_growvector(ls->L, f->locvars, fs->ndebugvars, f->sizelocvars, LocVar, SHRT_MAX, ...)
837	    // In Rust, Vec grows automatically; just push a placeholder if needed.
838	    let idx = fs.ndebugvars as usize;
839	    while fs.f.locvars.len() <= idx {
840	        // C: f->locvars[oldsize++].varname = NULL
841	        fs.f.locvars.push(LocalVar {
842	            varname: varname.clone(), // placeholder; overwritten below
843	            startpc: 0,
844	            endpc: 0,
845	        });
846	    }
847	    fs.f.locvars[idx].varname = varname;
848	    fs.f.locvars[idx].startpc = fs.pc;
849	    // C: luaC_objbarrier(ls->L, f, varname) — no-op in Phase A
850	    let result = fs.ndebugvars as i32;
851	    fs.ndebugvars += 1;
852	    Ok(result)
853	}
