855	/// C: static int new_localvar(LexState *ls, TString *name)
856	/// Creates a new local variable entry in dyd.actvar.
857	/// Returns the variable's index relative to fs->firstlocal.
858	fn new_local_var(
859	    ls: &mut LexState,
860	    state: &mut LuaState,
861	    name: GcRef<LuaString>,
862	) -> Result<i32, LuaError> {
863	    // C: checklimit(fs, dyd->actvar.n + 1 - fs->firstlocal, MAXVARS, "local variables")
864	    let fs = ls.fs.as_ref().unwrap();
865	    let n = ls.dyd.actvar.len() as i32;
866	    let first_local = fs.firstlocal;
867	    check_limit(fs, n + 1 - first_local, MAX_VARS, "local variables")?;
868	
869	    // C: luaM_growvector(...) — Vec grows automatically
870	    // C: var = &dyd->actvar.arr[dyd->actvar.n++]
871	    let mut var = VarDesc::default();
872	    var.kind = VarKind::Reg;
873	    var.name = Some(name);
874	    ls.dyd.actvar.push(var);
875	    let result = ls.dyd.actvar.len() as i32 - 1 - first_local;
876	    Ok(result)
877	}
