890	/// C: static int reglevel(FuncState *fs, int nvar)
891	/// Converts a compiler-index level to its register number.
892	fn reg_level(ls: &LexState, fs: &FuncState, nvar: i32) -> i32 {
893	    // C: search backwards for the highest variable in a register
894	    let mut nvar = nvar;
895	    while nvar > 0 {
896	        nvar -= 1;
897	        let vd = get_local_var_desc(ls, fs, nvar);
898	        if vd.kind != VarKind::CompileTimeConst {
899	            return vd.ridx as i32 + 1;
900	        }
901	    }
902	    0
903	}
