912	/// C: static LocVar *localdebuginfo(FuncState *fs, int vidx)
913	/// Returns a mutable reference to the debug-info entry for variable `vidx`,
914	/// or `None` if it is a compile-time constant (no debug info).
915	fn local_debug_info<'a>(ls: &LexState, fs: &'a mut FuncState, vidx: i32) -> Option<&'a mut LocalVar> {
916	    let vd = get_local_var_desc(ls, fs, vidx);
917	    if vd.kind == VarKind::CompileTimeConst {
918	        return None; // C: return NULL
919	    }
920	    let idx = vd.pidx as usize;
921	    debug_assert!((idx as i16) < fs.ndebugvars);
922	    // TODO(port): borrow conflict — vd borrows ls immutably, idx is a copy; safe to proceed.
923	    Some(&mut fs.f.locvars[idx])
924	}
