935	/// C: static void check_readonly(LexState *ls, expdesc *e)
936	/// Raises an error if expression `e` describes a read-only variable.
937	fn check_readonly(ls: &mut LexState, state: &mut LuaState, e: &ExprDesc) -> Result<(), LuaError> {
938	    // C: FuncState *fs = ls->fs;  TString *varname = NULL;
939	    let varname: Option<GcRef<LuaString>> = {
940	        let fs = ls.fs.as_ref().unwrap();
941	        match e.k {
942	            ExprKind::Const => {
943	                // C: varname = ls->dyd->actvar.arr[e->u.info].vd.name
944	                ls.dyd.actvar[e.u.info as usize].name.clone()
945	            }
946	            ExprKind::Local => {
947	                let vd = get_local_var_desc(ls, fs, e.u.var_vidx as i32);
948	                if vd.kind != VarKind::Reg {
949	                    vd.name.clone()
950	                } else {
951	                    None
952	                }
953	            }
954	            ExprKind::UpVal => {
955	                let up = &fs.f.upvalues[e.u.info as usize];
956	                if VarKind::from_u8(up.kind) != VarKind::Reg {
957	                    up.name.clone()
958	                } else {
959	                    None
960	                }
961	            }
962	            _ => None,
963	        }
964	    };
965	    if let Some(vname) = varname {
966	        // C: luaK_semerror(ls, luaO_pushfstring(..., "attempt to assign to const variable '%s'", ...))
967	        // TODO(port): getstr(varname) → varname.as_bytes()
968	        return Err(LuaError::syntax(format_args!(
969	            "attempt to assign to const variable"
970	        )));
971	    }
972	    Ok(())
973	}
