975	/// C: static void adjustlocalvars(LexState *ls, int nvars)
976	/// Starts the scope for the last `nvars` created variables.
977	fn adjust_local_vars(ls: &mut LexState, state: &mut LuaState, nvars: i32) -> Result<(), LuaError> {
978	    // Extract needed data to avoid borrow conflict with ls.fs and ls.dyd
979	    let first_local = ls.fs.as_ref().unwrap().firstlocal;
980	    let nactvar_start = ls.fs.as_ref().unwrap().nactvar as i32;
981	    let mut reglevel_val = {
982	        let fs = ls.fs.as_ref().unwrap();
983	        reg_level(ls, fs, fs.nactvar as i32)
984	    };
985	
986	    for i in 0..nvars {
987	        let vidx = nactvar_start + i;
988	        ls.fs.as_mut().unwrap().nactvar += 1;
989	        // C: var->vd.ridx = reglevel++; var->vd.pidx = registerlocalvar(...)
990	        let var_name = ls.dyd.actvar[(first_local + vidx) as usize].name.clone();
991	        ls.dyd.actvar[(first_local + vidx) as usize].ridx = reglevel_val as u8;
992	        reglevel_val += 1;
993	        if let Some(vn) = var_name {
994	            let mut fs_box = ls.fs.take().unwrap();
995	            let pidx_result = register_local_var(ls, state, &mut fs_box, vn);
996	            ls.fs = Some(fs_box);
997	            let pidx = pidx_result?;
998	            ls.dyd.actvar[(first_local + vidx) as usize].pidx = pidx as i16;
999	        } else {
1000	            // TODO(port): variable has no name — shouldn't happen in valid source
1001	        }
1002	    }
1003	    Ok(())
1004	}
