1006	/// C: static void removevars(FuncState *fs, int tolevel)
1007	/// Closes scope for all variables above `tolevel`, updating their endpc.
1008	fn remove_vars(ls: &mut LexState, fs: &mut FuncState, tolevel: i32) {
1009	    // C: fs->ls->dyd->actvar.n -= (fs->nactvar - tolevel)
1010	    let delta = fs.nactvar as i32 - tolevel;
1011	    if delta > 0 {
1012	        let new_len = ls.dyd.actvar.len().saturating_sub(delta as usize);
1013	        ls.dyd.actvar.truncate(new_len);
1014	    }
1015	    while fs.nactvar as i32 > tolevel {
1016	        fs.nactvar -= 1;
1017	        // C: LocVar *var = localdebuginfo(fs, --fs->nactvar); if (var) var->endpc = fs->pc
1018	        let nactvar = fs.nactvar as i32;
1019	        let vd_kind = {
1020	            // need to check kind without holding a borrow across the mut borrow below
1021	            let first_local = fs.firstlocal;
1022	            ls.dyd.actvar.get((first_local + nactvar) as usize)
1023	                .map(|v| v.kind)
1024	                .unwrap_or(VarKind::Reg)
1025	        };
1026	        if vd_kind != VarKind::CompileTimeConst {
1027	            let vd_pidx = {
1028	                let first_local = fs.firstlocal;
1029	                ls.dyd.actvar.get((first_local + nactvar) as usize)
1030	                    .map(|v| v.pidx)
1031	                    .unwrap_or(0)
