        patchlistaux(fs, ls, e.f, final_pc, reg as u32, p_f)?;
        patchlistaux(fs, ls, e.t, final_pc, reg as u32, p_t)?;
    }
    e.f = NO_JUMP;
    e.t = NO_JUMP;

